from typing import Optional

import typer

from Sentinel_Deploy_New.run_sentinel_cloud import synchronizer
from Sentinel_Deploy_New.run_sentinel_cloud import open_url_and_display
from Sentinel_Deploy_New.run_sentinel_cloud import _Client
from Sentinel_Deploy_New.run_sentinel_cloud import config
from modal_proto import api_pb2


@synchronizer.create_blocking
async def dashboard(
    object_id: Optional[str] = typer.Argument(None, help="Open a view for a specific object."),
):
    """Open the Modal Dashboard in a web browser."""
    if object_id:
        url = f"https://modal.com/id/{object_id}"
    else:
        env = config.get("environment")
        request = api_pb2.WorkspaceDashboardUrlRequest(environment_name=env)
        client = await _Client.from_env()
        response = await client.stub.WorkspaceDashboardUrlGet(request)
        url = response.url

    open_url_and_display(url, "dashboard")
